var items = $input.all();
var BATCH_SIZE = 4;
var output = [];
for (var start = 0; start < items.length; start += BATCH_SIZE) {
  var batch = items.slice(start, start + BATCH_SIZE);
  var batchNum = Math.floor(start / BATCH_SIZE) + 1;
  var emails = batch.map(function(item, idx) {
    var j = item.json;
    var n = start + idx + 1;
    var fromObj = j.from || {};
    var from = fromObj.text || (fromObj.value && fromObj.value[0] && fromObj.value[0].address) || (typeof j.from === "string" ? j.from : "") || "Unknown Sender";
    var toObj = j.to || {};
    var to = toObj.text || (typeof j.to === "string" ? j.to : "") || "";
    var subject = j.subject || "(no subject)";
    var date = j.date || j.internalDate || "";
    var body = (j.text || j.textPlain || j.snippet || "").toString().slice(0, 6000);
    var binKeys = Object.keys(item.binary || {});
    var attNameParts = [];
    for (var ai = 0; ai < binKeys.length; ai++) {
      var bk = binKeys[ai];
      var bval = (item.binary || {})[bk];
      attNameParts.push(bval ? (bval.fileName || bk) : bk);
    }
    return { n: n, from: from, to: to, subject: subject, date: date, body: body, attCount: binKeys.length, attNames: attNameParts };
  });
  var NL = "\n";
  var emailParts = [];
  for (var ei = 0; ei < emails.length; ei++) {
    var e = emails[ei];
    var t = "===== EMAIL [#" + e.n + "] =====" + NL;
    t += "From: " + e.from + NL + "To: " + e.to + NL + "Date: " + e.date + NL + "Subject: " + e.subject + NL;
    if (e.attCount > 0) {
      var attStr = "";
      for (var ai2 = 0; ai2 < e.attNames.length; ai2++) { if (ai2 > 0) attStr += ", "; attStr += e.attNames[ai2]; }
      t += "Attachments (" + e.attCount + "): " + attStr + NL;
    }
    t += NL + "Body:" + NL + e.body + NL;
    emailParts.push(t);
  }
  var emailsText = "";
  for (var pi = 0; pi < emailParts.length; pi++) { if (pi > 0) emailsText += NL + NL; emailsText += emailParts[pi]; }
  output.push({ json: { batchNum: batchNum, batchCount: batch.length, emails: emails, emailsText: emailsText, totalEmails: items.length } });
}
return output;

var batchItems = $input.all();
var originalEmails = $("Get Emails").all();
var allBatchSummaries = [];
for (var bi = 0; bi < batchItems.length; bi++) {
  allBatchSummaries.push({ batchNum: bi + 1, summary: batchItems[bi].json.text || "" });
}
var allEmails = [];
for (var ei = 0; ei < originalEmails.length; ei++) {
  var item = originalEmails[ei];
  var j = item.json;
  var emailNum = ei + 1;
  var fromObj = j.from || {};
  var from = fromObj.text || (fromObj.value && fromObj.value[0] && fromObj.value[0].address) || (typeof j.from === "string" ? j.from : "") || "Unknown Sender";
  var toObj = j.to || {};
  var to = toObj.text || (typeof j.to === "string" ? j.to : "") || "";
  var subject = j.subject || "(no subject)";
  var date = j.date || j.internalDate || "";
  var plainBody = (j.text || j.textPlain || j.snippet || "").toString();
  var binKeys = Object.keys(item.binary || {});
  var attachments = [];
  for (var ai = 0; ai < binKeys.length; ai++) {
    var bk = binKeys[ai];
    var bval = (item.binary || {})[bk];
    attachments.push({ name: bval ? (bval.fileName || bk) : bk, mimeType: bval ? (bval.mimeType || "application/octet-stream") : "application/octet-stream" });
  }
  allEmails.push({ emailNum: emailNum, from: from, to: to, subject: subject, date: date, plainBody: plainBody, attachments: attachments });
}
var summariesText = "";
for (var si = 0; si < allBatchSummaries.length; si++) {
  if (si > 0) summariesText += "\n\n";
  summariesText += "=== BATCH " + allBatchSummaries[si].batchNum + " SUMMARY ===" + "\n" + allBatchSummaries[si].summary;
}
return [{ json: { totalEmails: originalEmails.length, totalBatches: allBatchSummaries.length, allEmails: allEmails, allBatchSummaries: allBatchSummaries, summariesText: summariesText } }];

