var masterText = $("Master Summary (AI)").first().json.text || "";

var compiled = $("Compile All").first().json;
var originalEmails = $("Get Emails").all();

var allBinary = {};
var attachmentIndex = [];
var globalAttIdx = 0;
for (var emailIdx = 0; emailIdx < compiled.allEmails.length; emailIdx++) {
  var email = compiled.allEmails[emailIdx];
  var origItem = originalEmails[emailIdx];
  if (!origItem) continue;
  var binData = origItem.binary || {};
  var binKeys = Object.keys(binData);
  for (var bki = 0; bki < binKeys.length; bki++) {
    if (globalAttIdx >= 50) break;
    var key = binKeys[bki];
    var b = binData[key];
    var paddedIdx = globalAttIdx < 10 ? "0" + globalAttIdx : "" + globalAttIdx;
    var newKey = "att_" + paddedIdx;
    allBinary[newKey] = b;
    attachmentIndex.push({ key: newKey, name: b ? (b.fileName || key) : key, mimeType: b ? (b.mimeType || "") : "", emailNum: email.emailNum, emailSubject: email.subject, emailFrom: email.from });
    globalAttIdx++;
  }
}

function escHtml(str) {
  return (str || "").replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

function citationLink(n) {
  return '<a href="#email-' + n + '" class="cite" title="Jump to Email #' + n + '" style="display:inline-block;background:#ebf8ff;color:#2b6cb0;padding:2px 7px;border-radius:10px;font-size:11px;font-weight:700;margin:0 1px;text-decoration:none;cursor:pointer">[#' + n + ']</a>';
}

function summaryToHtml(text) {
